attempt_1_commands:
awk '{
  if (match($0, /^[[:space:]]*#/) && /\/dev\/shm/) {
    line = substr($0, RSTART + RLENGTH);
    $0 = line;
  }
  if ($2 == "/dev/shm" && $3 == "tmpfs") {
    if ($4 !~ /noexec/) {
      $4 = $4 ",noexec";
    }
  }
  print $0;
}' /etc/fstab > /tmp/fstab.tmp && mv /tmp/fstab.tmp /etc/fstab; mount -o remount /dev/shm; mount -o remount /dev/shm; mount -o remount /dev/shm; mount -o remount /dev/shm; mount -o remount /dev/shm; mount -o remount /dev/shm
